const parts = [$.input.question, $.input.matchThreshold];
const staticTerms = "SELECT id, content, metadata, similarity FROM match_documents('', , 10)";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

function fb(a, b) { if (a) { return a; } return b; }
var resp = fb($.steps.searchDocs.response, {});
var rows = fb(fb(fb(resp.rows, resp.result), resp.data), []);
var question = $.input.question;

var context = '';
var docCount = 0;

if (Array.isArray(rows)) {
  rows.forEach(function(row, i) {
    var content = fb(fb(row.content, row.text), JSON.stringify(row));
    var similarity = fb(row.similarity, 'N/A');
    var metadata = fb(row.metadata, {});
    context += '--- Document ' + (i + 1) + ' (similarity: ' + similarity + ') ---\n';
    if (metadata.source) context += 'Source: ' + metadata.source + '\n';
    context += content.slice(0, 2000) + '\n\n';
    docCount++;
  });
}

return { context: context, docCount: docCount, question: question };

var data = $.steps.compileContext.output;

var prompt = 'You are a documentation expert assistant. Answer the user\'s question using ONLY the provided context from the documentation database. If the context does not contain enough information, say so clearly.\n\n';
prompt += 'RETRIEVED DOCUMENTATION (' + data.docCount + ' documents):\n\n';
prompt += data.context + '\n';
prompt += 'USER QUESTION: ' + data.question + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Answer based on the documentation context above\n';
prompt += '- Cite specific documents when possible\n';
prompt += '- If the docs don\'t cover this topic, say so\n';
prompt += '- Be precise and technical when appropriate\n';
prompt += '- Suggest related topics the user might want to explore\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "answer": "your detailed answer",\n';
prompt += '  "confidence": "high/medium/low based on documentation coverage",\n';
prompt += '  "sources": ["source 1 reference", "source 2 reference"],\n';
prompt += '  "relatedTopics": ["topic 1", "topic 2"],\n';
prompt += '  "caveats": "any caveats or limitations of the answer"\n';
prompt += '}';

return { prompt: prompt };

function fb(a, b) { if (a) { return a; } return b; }
var raw = fb($.steps.aiAnalysis.output, '');
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, confidence: 'unknown', sources: [], relatedTopics: [] }; }

function fb(a, b) { if (a) { return a; } return b; }
var ai = $.steps.parseResponse.output;
var question = $.input.question;
var docCount = $.steps.compileContext.output.docCount;

var confidenceIcon = ':white_circle:';
if (ai.confidence === 'high') confidenceIcon = ':large_green_circle:';
if (ai.confidence === 'medium') confidenceIcon = ':large_orange_circle:';

var blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ':books: Documentation Expert', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + question } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: fb(ai.answer, 'No answer could be generated.') } });

blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: confidenceIcon + ' *Confidence:* ' + (fb(ai.confidence, 'unknown')) + '  |  *Docs matched:* ' + docCount }] });

var sources = fb(ai.sources, []);
if (sources.length > 0) {
  var sourceText = '*Sources:*\n';
  sources.forEach(function(s) { sourceText += '  - ' + s + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: sourceText } });
}

var related = fb(ai.relatedTopics, []);
if (related.length > 0) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':mag: *Related:* ' + related.join(', ') }] });
}

if (ai.caveats) {
  blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: ':warning: ' + ai.caveats }] });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Supabase RAG + Claude AI + One CLI' }] });

var fallback = 'Docs Expert — ' + question;
return { blocks: blocks, fallback: fallback };
